import { useEffect, useState, useRef } from "react";
import axios from "axios";
import { MapContainer, TileLayer, Marker, Popup, useMap, Circle } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import L from "leaflet";

// Fix Leaflet default icon
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png",
  iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png",
  shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png",
});

// Color-coded icons by type
const createIcon = (color) =>
  new L.DivIcon({
    className: "",
    html: `<div style="width:14px;height:14px;border-radius:50%;background:${color};border:2px solid white;box-shadow:0 0 6px ${color}99"></div>`,
    iconSize: [14, 14],
    iconAnchor: [7, 7],
  });

const typeConfig = {
  accident: { color: "#ef4444", icon: "🚗", bg: "#fef2f2", label: "Accident" },
  medical:  { color: "#8b5cf6", icon: "🏥", bg: "#f5f3ff", label: "Medical"  },
  robbery:  { color: "#f59e0b", icon: "🔒", bg: "#fffbeb", label: "Robbery"  },
  attack:   { color: "#f97316", icon: "⚠️", bg: "#fff7ed", label: "Attack"   },
  default:  { color: "#3b82f6", icon: "📍", bg: "#eff6ff", label: "Alert"    },
};

const getTypeConfig = (type) => typeConfig[type?.toLowerCase()] || typeConfig.default;

function ChangeMapView({ coords }) {
  const map = useMap();
  useEffect(() => {
    if (coords) map.setView(coords, 16, { animate: true });
  }, [coords, map]);
  return null;
}

export default function Admin() {
  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [filter, setFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [newAlertCount, setNewAlertCount] = useState(0);
  const prevAlertIds = useRef([]);

  const loadAlerts = () => {
    axios
      .get("http://127.0.0.1:8000/api/admin-alerts/")
      .then((res) => {
        const data = res.data;
        const activeNow = data.filter((a) => a.status !== "resolved").map((a) => a.id);
        const newOnes = activeNow.filter((id) => !prevAlertIds.current.includes(id));
        if (newOnes.length > 0) setNewAlertCount((c) => c + newOnes.length);
        prevAlertIds.current = activeNow;
        setAlerts(data);
        setLoading(false);
      })
      .catch(() => {
        setError("Failed to load alerts");
        setLoading(false);
      });
  };

  useEffect(() => {
    loadAlerts();
    const interval = setInterval(loadAlerts, 15000);
    return () => clearInterval(interval);
  }, []);

  const resolveAlert = (id) => {
    axios
      .post(`http://127.0.0.1:8000/api/resolve-api/${id}/`)
      .then(() => loadAlerts())
      .catch((err) => console.log("Resolve error:", err));
  };

  const active = alerts.filter((a) => a.status !== "resolved");
  const resolved = alerts.filter((a) => a.status === "resolved");

  // Stats
  const stats = {
    total: alerts.length,
    active: active.length,
    resolved: resolved.length,
    types: Object.entries(
      active.reduce((acc, a) => {
        const t = a.emergency_type || "default";
        acc[t] = (acc[t] || 0) + 1;
        return acc;
      }, {})
    ),
  };

  if (loading) return (
    <div style={styles.loadingScreen}>
      <div style={styles.loadingSpinner}></div>
      <p style={{ color: "#94a3b8", marginTop: 16, fontFamily: "'DM Sans', sans-serif" }}>Loading alerts...</p>
      <style>{spinnerCSS}</style>
    </div>
  );

  if (error) return (
    <div style={styles.loadingScreen}>
      <span style={{ fontSize: 40 }}>⚠️</span>
      <p style={{ color: "#ef4444", marginTop: 12 }}>{error}</p>
    </div>
  );

  return (
    <div style={styles.page}>
      <style>{globalCSS}</style>

      {/* HEADER */}
      <div style={styles.header}>
        <div>
          <div style={styles.headerBadge}>LIVE MONITORING</div>
          <h1 style={styles.title}>Admin Control Center</h1>
          <p style={styles.subtitle}>Hyderabad Emergency Response Dashboard</p>
        </div>
        <div style={styles.headerRight}>
          {newAlertCount > 0 && (
            <div style={styles.newAlertBadge} onClick={() => setNewAlertCount(0)}>
              🔔 {newAlertCount} new alert{newAlertCount > 1 ? "s" : ""}
            </div>
          )}
          <div style={styles.refreshInfo}>
            <span style={styles.pulseDot}></span>
            Auto-refresh every 15s
          </div>
          <button style={styles.refreshBtn} onClick={loadAlerts}>↻ Refresh</button>
        </div>
      </div>

      {/* STATS CARDS */}
      <div style={styles.statsGrid}>
        <StatCard label="Total Alerts" value={stats.total} icon="📋" color="#3b82f6" />
        <StatCard label="Active Now" value={stats.active} icon="🚨" color="#ef4444" pulse={stats.active > 0} />
        <StatCard label="Resolved" value={stats.resolved} icon="✅" color="#10b981" />
        <StatCard label="Alert Types" value={stats.types.length} icon="📊" color="#8b5cf6" />
      </div>

      {/* TYPE BREAKDOWN */}
      {stats.types.length > 0 && (
        <div style={styles.typeBreakdown}>
          {stats.types.map(([type, count]) => {
            const cfg = getTypeConfig(type);
            return (
              <div key={type} style={{ ...styles.typeChip, background: cfg.bg, borderColor: cfg.color + "44" }}>
                <span>{cfg.icon}</span>
                <span style={{ fontWeight: 600, color: cfg.color }}>{count}</span>
                <span style={{ color: "#64748b", fontSize: 12 }}>{cfg.label}</span>
              </div>
            );
          })}
        </div>
      )}

      {/* MAP */}
      <div style={styles.mapWrapper}>
        <div style={styles.mapHeader}>
          <h2 style={styles.sectionTitle}>🗺️ Live Incident Map</h2>
          <div style={styles.mapLegend}>
            {Object.entries(typeConfig).filter(([k]) => k !== "default").map(([type, cfg]) => (
              <span key={type} style={styles.legendItem}>
                <span style={{ ...styles.legendDot, background: cfg.color }}></span>
                {cfg.label}
              </span>
            ))}
          </div>
        </div>
        <MapContainer
          center={[17.38, 78.48]}
          zoom={12}
          style={{ height: 380, borderRadius: "0 0 16px 16px" }}
        >
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          <ChangeMapView coords={selectedLocation} />

          {active.map((a) =>
            a.latitude && a.longitude ? (
              <Marker
                key={a.id}
                position={[a.latitude, a.longitude]}
                icon={createIcon(getTypeConfig(a.emergency_type).color)}
              >
                <Popup>
                  <div style={{ fontFamily: "sans-serif", minWidth: 160 }}>
                    <div style={{ fontWeight: 700, marginBottom: 4 }}>
                      {getTypeConfig(a.emergency_type).icon} {a.message}
                    </div>
                    <div style={{ fontSize: 12, color: "#64748b" }}>Device: {a.device_id}</div>
                    <div style={{ fontSize: 12, color: "#64748b" }}>
                      {new Date(a.timestamp).toLocaleString()}
                    </div>
                    <div style={{ marginTop: 6 }}>
                      <span style={{
                        background: getTypeConfig(a.emergency_type).color,
                        color: "white", padding: "2px 8px", borderRadius: 10, fontSize: 11
                      }}>
                        {a.emergency_type}
                      </span>
                    </div>
                  </div>
                </Popup>
              </Marker>
            ) : null
          )}

          {selectedLocation && (
            <Circle
              center={selectedLocation}
              radius={200}
              pathOptions={{ color: "#f97316", fillColor: "#f97316", fillOpacity: 0.15 }}
            />
          )}
        </MapContainer>
      </div>

      {/* ACTIVE ALERTS */}
      <div style={styles.section}>
        <div style={styles.sectionHeader}>
          <h2 style={styles.sectionTitle}>
            🚨 Active Alerts
            {active.length > 0 && <span style={styles.countBadge}>{active.length}</span>}
          </h2>
          <SearchBar value={search} onChange={setSearch} />
        </div>
        <AlertTable
          alerts={active}
          resolveAlert={resolveAlert}
          setSelectedLocation={setSelectedLocation}
          search={search}
          showResolve
        />
      </div>

      {/* RESOLVED HISTORY */}
      <div style={styles.section}>
        <div style={styles.sectionHeader}>
          <h2 style={styles.sectionTitle}>📋 Resolved History</h2>
          <div style={styles.filterRow}>
            {["all", "accident", "medical", "robbery", "attack"].map((f) => (
              <button
                key={f}
                style={{ ...styles.filterBtn, ...(filter === f ? styles.filterBtnActive : {}) }}
                onClick={() => setFilter(f)}
              >
                {f.charAt(0).toUpperCase() + f.slice(1)}
              </button>
            ))}
          </div>
        </div>
        <AlertTable
          alerts={resolved.filter((a) => filter === "all" || a.emergency_type === filter)}
          setSelectedLocation={setSelectedLocation}
          search=""
        />
      </div>
    </div>
  );
}

