function StatCard({ label, value, icon, color, pulse }) {
  return (
    <div style={{ ...styles.statCard, borderTop: `3px solid ${color}` }} className="stat-card">
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
