}

// ── SEARCH BAR ─────────────────────────────────────────────────────────────────
function SearchBar({ value, onChange }) {
  return (
    <div style={styles.searchWrap}>
      <span style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", color: "#94a3b8" }}>🔍</span>
      <input
        style={styles.searchInput}
        placeholder="Search device, message..."
        value={value}
        onChange={(e) => onChange(e.target.value)}
      />
    </div>
  );
}

// ── ALERT TABLE ────────────────────────────────────────────────────────────────
function AlertTable({ alerts, resolveAlert, setSelectedLocation, search, showResolve }) {
  const navigateToLocation = (lat, lon) => {
    window.open(`https://www.google.com/maps/dir/?api=1&destination=${lat},${lon}`, "_blank");
  };

  const filtered = search
    ? alerts.filter(
        (a) =>
          a.device_id?.toLowerCase().includes(search.toLowerCase()) ||
          a.message?.toLowerCase().includes(search.toLowerCase())
      )
    : alerts;

  if (!filtered.length) return (
    <div style={styles.emptyState}>
      <span style={{ fontSize: 36 }}>📭</span>
      <p style={{ color: "#94a3b8", marginTop: 8 }}>No alerts found</p>
    </div>
  );

  return (
    <div style={styles.tableWrap}>
      <table style={styles.table}>
        <thead>
          <tr style={styles.thead}>
            <th style={styles.th}>Device</th>
            <th style={styles.th}>Type</th>
            <th style={styles.th}>Message</th>
            <th style={styles.th}>Location</th>
            <th style={styles.th}>Status</th>
            <th style={styles.th}>Time</th>
            {showResolve && <th style={styles.th}>Action</th>}
          </tr>
        </thead>
        <tbody>
          {filtered.map((a) => {
            const cfg = getTypeConfig(a.emergency_type);
            return (
              <tr key={a.id} style={styles.tr} className="alert-row">
                <td style={styles.td}>
                  <span style={styles.deviceChip}>{a.device_id}</span>
                </td>

                <td style={styles.td}>
                  <span style={{ ...styles.typeTag, background: cfg.bg, color: cfg.color, borderColor: cfg.color + "33" }}>
                    {cfg.icon} {cfg.label}
                  </span>
                </td>

                <td style={{ ...styles.td, maxWidth: 200 }}>{a.message}</td>

                <td style={styles.td}>
                  <div style={{ fontSize: 11, color: "#94a3b8", marginBottom: 4 }}>
                    {parseFloat(a.latitude).toFixed(4)}, {parseFloat(a.longitude).toFixed(4)}
                  </div>
                  <div style={{ display: "flex", gap: 4 }}>
                    <button style={styles.navBtn} onClick={() => navigateToLocation(a.latitude, a.longitude)}>
                      🧭 Navigate
                    </button>
                    <button style={styles.viewBtn} onClick={() => setSelectedLocation([a.latitude, a.longitude])}>
                      🗺️ Map
                    </button>
                  </div>
                </td>

                <td style={styles.td}>
                  <span style={{
                    padding: "4px 10px", borderRadius: 20, fontSize: 11, fontWeight: 600,
                    background: a.status === "resolved" ? "#dcfce7" : "#fee2e2",
                    color: a.status === "resolved" ? "#16a34a" : "#dc2626",
                  }}>
                    {a.status === "resolved" ? "✓ Resolved" : "● Active"}
                  </span>
                </td>

                <td style={{ ...styles.td, fontSize: 12, color: "#64748b", whiteSpace: "nowrap" }}>
                  {new Date(a.timestamp).toLocaleString()}
                </td>

                {showResolve && (
                  <td style={styles.td}>
                    <button style={styles.resolveBtn} onClick={() => resolveAlert(a.id)}>
                      ✓ Resolve
                    </button>
                  </td>
                )}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

